1	//! Shared test helpers for dual-repo integration tests.
2	//!
3	//! Provides a `Fixture` that wraps `crate::init::init_with_symlink`
4	//! plus a per-process unique-tempdir helper so parallel tests don't
5	//! collide. Lifted out of the `sync` test module (originally inline at
6	//! `sync.rs:521–560`) so `push`'s tests (0.37.0) and any future
7	//! subcommand's tests can sit on the same harness without
8	//! copy-paste drift.
9	//!
10	//! Test-only — the whole module is gated at its declaration site via
11	//! `#[cfg(test)] mod test_helpers;`.
12	
13	use std::fs;
14	use std::path::PathBuf;
15	use std::sync::atomic::{AtomicU64, Ordering};
16	use std::time::{SystemTime, UNIX_EPOCH};
17	
18	use crate::common::write_file;
19	use crate::config::RepoSelector;
20	use crate::init::{InitArgs, init_with_symlink};
21	use crate::options_flags::account::AccountOption;
22	use crate::options_flags::config::ConfigOption;
23	use crate::options_flags::provision_bundle::ProvisionOptionFlagBundle;
24	use crate::options_flags::repo::RepoOption;
25	use crate::options_flags::scope::{ScopeKind, ScopeOption};
26	use crate::options_flags::use_template::UseTemplateOption;
27	use crate::test_tmp_root::{resolve_tmp_root, should_keep_tempdir};
28	
29	/// Per-process counter so same-nanosecond tempdir collisions yield
30	/// distinct paths when tests run in parallel.
31	static COUNTER: AtomicU64 = AtomicU64::new(0);
32	
33	/// Build a unique tempdir path for a test fixture.
34	///
35	/// Combines a nanosecond timestamp with a per-process atomic counter
36	/// so parallel tests and same-nanosecond collisions both yield
37	/// distinct paths. Prefix is `vc-x1-test-<tag>-<ts>-<n>` so callers
38	/// from different subcommand tests stay discoverable in `$TMPDIR`.
39	pub fn unique_base(tag: &str) -> PathBuf {
40	    let ts = SystemTime::now()
41	        .duration_since(UNIX_EPOCH)
42	        .map(|d| d.as_nanos())
43	        .unwrap_or(0); // OK: clock error → 0 is harmless for unique tempdir naming
44	    let n = COUNTER.fetch_add(1, Ordering::SeqCst);
45	    resolve_tmp_root().join(format!("vc-x1-test-{tag}-{ts}-{n}"))
46	}
47	
48	/// Owned dual-repo fixture with RAII cleanup.
49	///
